lemma GcdBound(a: int, b: int)
  requires 0 < a < b
  ensures Gcd(a, b) * 2 <= b
  decreases b, a
{
  assert a % b == a;
  assert Gcd(a, b) == Gcd(b, a);

  var r := b % a;
  if r == 0 {
    assert Gcd(b, a) == a;
    var k := b / a;
    assert b == a * k;
    assert k >= 2;
    MulLeMonotone(a, 2, k);
